import numpy as np

class Board:
    def __init__(self):
        self.board = self._initialize_board()

    def _initialize_board(self):
        board = np.zeros((8, 8), dtype=int)
        for row in range(3):
            for col in range(0, 8, 2):
                board[row, col] = 1
        for row in range(5, 8):
            for col in range(1, 9, 2):
                board[row, col] = -1
        return board

    def display(self):
        for row in self.board:
            print(" ".join(str(piece) for piece in row))

    def move_piece(self, from_pos, to_pos):
        x_from, y_from = from_pos
        x_to, y_to = to_pos

        if self.is_valid_move(from_pos, to_pos):
            piece = self.board[x_from, y_from]
            self.board[x_from, y_from] = 0
            self.board[x_to, y_to] = piece

            # Kinging logic
            if (piece == 1 and x_to == 7) or (piece == -1 and x_to == 0):
                self.king_piece((x_to, y_to))

    def is_valid_move(self, from_pos, to_pos):
        x_from, y_from = from_pos
        x_to, y_to = to_pos

        piece = self.board[x_from, y_from]

        if piece == 0:
            return False

        if abs(x_to - x_from) != abs(y_to - y_from):
            return False

        if (x_to < x_from and piece > 0) or (x_to > x_from and piece < 0):
            return False

        # Check for jumps
        jump_length = abs(x_to - x_from)

        if jump_length == 2:
            mid_x, mid_y = (x_from + x_to) // 2, (y_from + y_to) // 2
            if self.board[mid_x, mid_y] * piece > 0 or self.board[mid_x, mid_y] == 0:
                return False

        return True

    def king_piece(self, pos):
        x, y = pos
        piece = self.board[x, y]
        self.board[x, y] = piece if piece == 1 else -piece

    def has_winner(self):
        ones_count = np.sum(self.board == 1)
        minus_ones_count = np.sum(self.board == -1)

        return ones_count == 0 or minus_ones_count == 0
